using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.TestHelpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string databaseName = null)
        {
            databaseName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string databaseName = null)
        {
            var context = Create(databaseName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var dept1 = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 100000m,
                StartDate = new DateTime(2020, 1, 1)
            };
            var dept2 = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 200000m,
                StartDate = new DateTime(2019, 1, 1)
            };

            context.Departments.AddRange(dept1, dept2);
            context.SaveChanges();

            var instructor1 = new Instructor
            {
                ID = 1,
                LastName = "Abercrombie",
                FirstMidName = "Kim",
                HireDate = new DateTime(2010, 3, 11)
            };
            var instructor2 = new Instructor
            {
                ID = 2,
                LastName = "Fakhouri",
                FirstMidName = "Fadi",
                HireDate = new DateTime(2008, 7, 6)
            };

            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var course2 = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = 2
            };
            var course3 = new Course
            {
                CourseID = 1045,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = 2
            };

            context.Courses.AddRange(course1, course2, course3);
            context.SaveChanges();

            var student1 = new Student
            {
                ID = 10,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            var student2 = new Student
            {
                ID = 11,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            var student3 = new Student
            {
                ID = 12,
                LastName = "Barzdukas",
                FirstMidName = "Gytis",
                EnrollmentDate = new DateTime(2021, 9, 1)
            };

            context.Students.AddRange(student1, student2, student3);
            context.SaveChanges();

            context.Enrollments.AddRange(
                new Enrollment { CourseID = 1050, StudentID = 10, Grade = Grade.A },
                new Enrollment { CourseID = 4022, StudentID = 10, Grade = Grade.C },
                new Enrollment { CourseID = 1045, StudentID = 11, Grade = Grade.B }
            );
            context.SaveChanges();

            context.CourseAssignments.AddRange(
                new CourseAssignment { InstructorID = 1, CourseID = 1050 },
                new CourseAssignment { InstructorID = 2, CourseID = 4022 }
            );
            context.SaveChanges();
        }
    }
}

