using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        // Person is abstract; test via Student
        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John"
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        [Fact]
        public void FullName_WithEmptyFirstMidName_ReturnsLastNameComma()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = ""
            };

            Assert.Equal("Smith, ", student.FullName);
        }

        [Fact]
        public void ID_CanBeSetAndRetrieved()
        {
            var student = new Student { ID = 42 };
            Assert.Equal(42, student.ID);
        }

        [Fact]
        public void LastName_CanBeSetAndRetrieved()
        {
            var student = new Student { LastName = "Test" };
            Assert.Equal("Test", student.LastName);
        }

        [Fact]
        public void FirstMidName_CanBeSetAndRetrieved()
        {
            var student = new Student { FirstMidName = "First" };
            Assert.Equal("First", student.FirstMidName);
        }
    }
}

using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void EnrollmentDate_CanBeSetAndRetrieved()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Enrollments_DefaultsToNull()
        {
            var student = new Student();
            Assert.Null(student.Enrollments);
        }

        [Fact]
        public void Enrollments_CanBeSetAndRetrieved()
        {
            var enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1, CourseID = 100, StudentID = 1, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 200, StudentID = 1, Grade = Grade.B }
            };

            var student = new Student { Enrollments = enrollments };

            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Student_FullProperties()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2023, 1, 15)
            };

            Assert.Equal(1, student.ID);
            Assert.Equal("Doe", student.LastName);
            Assert.Equal("Jane", student.FirstMidName);
            Assert.Equal("Doe, Jane", student.FullName);
            Assert.Equal(new DateTime(2023, 1, 15), student.EnrollmentDate);
        }
    }
}

using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void HireDate_CanBeSetAndRetrieved()
        {
            var date = new DateTime(2015, 6, 15);
            var instructor = new Instructor { HireDate = date };
            Assert.Equal(date, instructor.HireDate);
        }

        [Fact]
        public void CourseAssignments_DefaultsToNull()
        {
            var instructor = new Instructor();
            Assert.Null(instructor.CourseAssignments);
        }

        [Fact]
        public void CourseAssignments_CanBeSetAndRetrieved()
        {
            var assignments = new List<CourseAssignment>
            {
                new CourseAssignment { InstructorID = 1, CourseID = 100 },
                new CourseAssignment { InstructorID = 1, CourseID = 200 }
            };

            var instructor = new Instructor { CourseAssignments = assignments };
            Assert.Equal(2, instructor.CourseAssignments.Count);
        }

        [Fact]
        public void OfficeAssignment_DefaultsToNull()
        {
            var instructor = new Instructor();
            Assert.Null(instructor.OfficeAssignment);
        }

        [Fact]
        public void OfficeAssignment_CanBeSetAndRetrieved()
        {
            var office = new OfficeAssignment { InstructorID = 1, Location = "Room 101" };
            var instructor = new Instructor { OfficeAssignment = office };

            Assert.NotNull(instructor.OfficeAssignment);
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void Instructor_FullName_Works()
        {
            var instructor = new Instructor
            {
                LastName = "Fakhouri",
                FirstMidName = "Fadi"
            };

            Assert.Equal("Fakhouri, Fadi", instructor.FullName);
        }
    }
}

using ContosoUniversity.Models;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class CourseTests
