using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void EnrollmentDate_CanBeSetAndRetrieved()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Enrollments_DefaultsToNull()
        {
            var student = new Student();
            Assert.Null(student.Enrollments);
        }

        [Fact]
        public void Enrollments_CanBeSetAndRetrieved()
        {
            var enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1, CourseID = 100, StudentID = 1, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, CourseID = 200, StudentID = 1, Grade = Grade.B }
            };

            var student = new Student { Enrollments = enrollments };

            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Student_FullProperties()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Doe",
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2023, 1, 15)
            };

            Assert.Equal(1, student.ID);
            Assert.Equal("Doe", student.LastName);
            Assert.Equal("Jane", student.FirstMidName);
            Assert.Equal("Doe, Jane", student.FullName);
            Assert.Equal(new DateTime(2023, 1, 15), student.EnrollmentDate);
        }
    }
}

