using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class DepartmentTests
    {
        [Fact]
        public void DepartmentID_CanBeSetAndRetrieved()
        {
            var dept = new Department { DepartmentID = 1 };
            Assert.Equal(1, dept.DepartmentID);
        }

        [Fact]
        public void Name_CanBeSetAndRetrieved()
        {
            var dept = new Department { Name = "Engineering" };
            Assert.Equal("Engineering", dept.Name);
        }

        [Fact]
        public void Budget_CanBeSetAndRetrieved()
        {
            var dept = new Department { Budget = 350000.50m };
            Assert.Equal(350000.50m, dept.Budget);
        }

        [Fact]
        public void StartDate_CanBeSetAndRetrieved()
        {
            var date = new DateTime(2020, 1, 1);
            var dept = new Department { StartDate = date };
            Assert.Equal(date, dept.StartDate);
        }

        [Fact]
        public void InstructorID_IsNullable()
        {
            var dept = new Department();
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void InstructorID_CanBeSetAndRetrieved()
        {
            var dept = new Department { InstructorID = 5 };
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void RowVersion_DefaultsToNull()
        {
            var dept = new Department();
            Assert.Null(dept.RowVersion);
        }

        [Fact]
        public void RowVersion_CanBeSetAndRetrieved()
        {
            var rowVersion = new byte[] { 1, 2, 3, 4, 5, 6, 7, 8 };
            var dept = new Department { RowVersion = rowVersion };
            Assert.Equal(rowVersion, dept.RowVersion);
        }

        [Fact]
        public void Administrator_NavigationProperty_CanBeSet()
        {
            var instructor = new Instructor { ID = 1, LastName = "Smith", FirstMidName = "John" };
            var dept = new Department { Administrator = instructor };

            Assert.NotNull(dept.Administrator);
            Assert.Equal("Smith, John", dept.Administrator.FullName);
        }

        [Fact]
        public void Courses_CanBeSetAndRetrieved()
        {
            var courses = new List<Course>
            {
                new Course { CourseID = 1, Title = "Test" },
                new Course { CourseID = 2, Title = "Test2" }
            };

            var dept = new Department { Courses = courses };
            Assert.Equal(2, dept.Courses.Count);
        }
    }
}

