using ContosoUniversity.Models;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class NotificationTests
    {
        [Fact]
        public void Id_CanBeSetAndRetrieved()
        {
            var n = new Notification { Id = 42 };
            Assert.Equal(42, n.Id);
        }

        [Fact]
        public void EntityType_CanBeSetAndRetrieved()
        {
            var n = new Notification { EntityType = "Student" };
            Assert.Equal("Student", n.EntityType);
        }

        [Fact]
        public void EntityId_CanBeSetAndRetrieved()
        {
            var n = new Notification { EntityId = "123" };
            Assert.Equal("123", n.EntityId);
        }

        [Fact]
        public void Operation_CanBeSetAndRetrieved()
        {
            var n = new Notification { Operation = "CREATE" };
            Assert.Equal("CREATE", n.Operation);
        }

        [Fact]
        public void Message_CanBeSetAndRetrieved()
        {
            var n = new Notification { Message = "Test message" };
            Assert.Equal("Test message", n.Message);
        }

        [Fact]
        public void CreatedAt_CanBeSetAndRetrieved()
        {
            var now = DateTime.Now;
            var n = new Notification { CreatedAt = now };
            Assert.Equal(now, n.CreatedAt);
        }

        [Fact]
        public void CreatedBy_CanBeSetAndRetrieved()
        {
            var n = new Notification { CreatedBy = "admin" };
            Assert.Equal("admin", n.CreatedBy);
        }

        [Fact]
        public void IsRead_DefaultsToFalse()
        {
            var n = new Notification();
            Assert.False(n.IsRead);
        }

        [Fact]
        public void IsRead_CanBeSetToTrue()
        {
            var n = new Notification { IsRead = true };
            Assert.True(n.IsRead);
        }

        [Fact]
        public void ReadAt_IsNullable_DefaultsToNull()
        {
            var n = new Notification();
            Assert.Null(n.ReadAt);
        }

        [Fact]
        public void ReadAt_CanBeSetAndRetrieved()
        {
            var now = DateTime.Now;
            var n = new Notification { ReadAt = now };
            Assert.Equal(now, n.ReadAt);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE)]
        [InlineData(EntityOperation.UPDATE)]
        [InlineData(EntityOperation.DELETE)]
        public void EntityOperation_AllValuesExist(EntityOperation op)
        {
            Assert.True(Enum.IsDefined(typeof(EntityOperation), op));
        }

        [Fact]
        public void EntityOperation_ToString_ReturnsCorrectNames()
