            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void AssignedCourseData_Assigned_DefaultsFalse()
        {
            var data = new AssignedCourseData();
            Assert.False(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties()
        {
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = new DateTime(2023, 9, 1),
                StudentCount = 5
            };

            Assert.Equal(new DateTime(2023, 9, 1), group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDate_IsNullable()
        {
            var group = new EnrollmentDateGroup();
            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_Properties()
        {
            var instructors = new List<Instructor> { new Instructor { LastName = "Test", FirstMidName = "A" } };
            var courses = new List<Course> { new Course { CourseID = 1, Title = "Test" } };
            var enrollments = new List<Enrollment> { new Enrollment { EnrollmentID = 1 } };

            var viewModel = new InstructorIndexData
            {
                Instructors = instructors,
                Courses = courses,
                Enrollments = enrollments
            };

            Assert.Single(viewModel.Instructors);
            Assert.Single(viewModel.Courses);
            Assert.Single(viewModel.Enrollments);
        }

        [Fact]
        public void InstructorIndexData_DefaultsToNull()
        {
            var viewModel = new InstructorIndexData();
            Assert.Null(viewModel.Instructors);
            Assert.Null(viewModel.Courses);
            Assert.Null(viewModel.Enrollments);
        }
    }
}

