using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using System.Threading;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from previous tests (static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue to avoid leaking between tests
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("created", notification.Message);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityId()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 42", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_DeleteOperation_MessageContainsDeleted()
        {
            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("deleted", notification.Message);
            Assert.Equal("DELETE", notification.Operation);
        }

        [Fact]
        public void SendNotification_CreateOperation_MessageFormat()
        {
            _service.SendNotification("Student", "1", "Jane Smith", EntityOperation.CREATE, "user");

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student 'Jane Smith' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_MessageFormat()
        {
            _service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE, "user");

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_MessageFormat()
        {
            _service.SendNotification("Department", "5", "Math", EntityOperation.DELETE, "user");

            var notification = _service.ReceiveNotification();
            Assert.Equal("Department 'Math' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_MessageFormat()
        {
            _service.SendNotification("Student", "99", null, EntityOperation.CREATE, "user");

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 99) has been created", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFO()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var n1 = _service.ReceiveNotification();
            var n2 = _service.ReceiveNotification();
            var n3 = _service.ReceiveNotification();

            Assert.Equal("A", n1.EntityType);
            Assert.Equal("B", n2.EntityType);
            Assert.Equal("C", n3.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            Assert.NotNull(first);

            var second = _service.ReceiveNotification();
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_WithAnyId_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(-1));
            Assert.Null(exception);

            exception = Record.Exception(() => _service.MarkAsRead(0));
            Assert.Null(exception);

            exception = Record.Exception(() => _service.MarkAsRead(999999));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            _service.SendNotification("Instructor", "5", EntityOperation.UPDATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("admin", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_EmptyDisplayName_FallsBackToId()
        {
            _service.SendNotification("Student", "1", "", EntityOperation.CREATE, "user");

            var notification = _service.ReceiveNotification();
            // Empty/whitespace display name => falls back to ID format
            Assert.Contains("ID: 1", notification.Message);
        }

        [Fact]
        public void SendNotification_WhitespaceDisplayName_FallsBackToId()
        {
            _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE, "user");

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 1", notification.Message);
        }
    }
}

using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);
            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            // 10 items, page size 3 => ceil(10/3) = 4
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);
            Assert.Equal(4, list.TotalPages);
        }

        [Fact]
        public void Constructor_TotalPages_ExactDivision()
        {
            // 9 items, page size 3 => ceil(9/3) = 3
            var list = new PaginatedList<int>(new List<int>(), 9, 1, 3);
            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void Constructor_TotalPages_SinglePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 10);
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void Constructor_TotalPages_ZeroItems()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.Equal(0, list.TotalPages);
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);
            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_OnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_OnSecondPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 3);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            // 10 items, 3 per page => 4 pages, on page 1
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            // 10 items, 3 per page => 4 pages, on page 4
            var list = new PaginatedList<int>(new List<int>(), 10, 4, 3);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenSinglePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 10);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(new List<int> { 6, 7, 8, 9, 10 }, result.ToList());
        }

        [Fact]
        public void Create_FirstPage()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(new List<int> { 1, 2, 3, 4, 5 }, result.ToList());
            Assert.False(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_LastPage_WithPartialItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(2, result.Count);
            Assert.Equal(3, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(new List<int> { 11, 12 }, result.ToList());
            Assert.True(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_WithEmptySource()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_WithStringType()
        {
            var source = new[] { "a", "b", "c", "d", "e" }.AsQueryable();
            var result = PaginatedList<string>.Create(source, 1, 2);

            Assert.Equal(2, result.Count);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal("a", result[0]);
            Assert.Equal("b", result[1]);
        }
    }
}

