using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };

            // Drain any leftover notifications
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }

            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            var json = result.Value;
            Assert.NotNull(json);

            // Parse the anonymous type
            var successProp = json.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(json));

            var countProp = json.GetType().GetProperty("count");
            Assert.Equal(0, (int)countProp.GetValue(json));
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Enqueue notifications via service
            var service = new NotificationService();
            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "admin");
            service.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE, "admin");

            var result = _controller.GetNotifications();
            var json = result.Value;

            var successProp = json.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(json));

            var countProp = json.GetType().GetProperty("count");
            Assert.Equal(2, (int)countProp.GetValue(json));
        }

        [Fact]
        public void GetNotifications_LimitsTo10()
        {
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications();
            var json = result.Value;

            var countProp = json.GetType().GetProperty("count");
            Assert.Equal(10, (int)countProp.GetValue(json));
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);
            var json = result.Value;

            var successProp = json.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(json));
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_DequeuesNotifications()
        {
            var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE);

            // First call should get the notification
            var result1 = _controller.GetNotifications();
            var json1 = result1.Value;
            var count1 = (int)json1.GetType().GetProperty("count").GetValue(json1);
            Assert.Equal(1, count1);

            // Second call should get empty
            var result2 = _controller.GetNotifications();
            var json2 = result2.Value;
            var count2 = (int)json2.GetType().GetProperty("count").GetValue(json2);
            Assert.Equal(0, count2);
        }
    }
}

