using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new StudentsController(_context);
            // Required for ViewBag to work
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.NotNull(model);
            Assert.True(model.Count > 0);
            // Default sort is by LastName ascending
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(string.Compare(model[i - 1].LastName, model[i].LastName) <= 0);
            }
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(string.Compare(model[i - 1].LastName, model[i].LastName) >= 0);
            }
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(model[i - 1].EnrollmentDate <= model[i].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.NotNull(model);
            for (int i = 1; i < model.Count; i++)
            {
                Assert.True(model[i - 1].EnrollmentDate >= model[i].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Carson", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchString_SetsPageTo1()
        {
            var result = _controller.Index(null, null, "a", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.NotNull(model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagCurrentSort()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            Assert.Equal("name_desc", _controller.ViewBag.CurrentSort);
        }

        [Fact]
        public void Index_SetsViewBagNameSortParm()
        {
            // When sortOrder is empty, NameSortParm should be "name_desc"
            _controller.Index(null, null, null, null);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);

            // When sortOrder is "name_desc", NameSortParm should be ""
            _controller.Index("name_desc", null, null, null);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_SetsViewBagDateSortParm()
        {
            // When sortOrder is "Date", DateSortParm should be "date_desc"
            _controller.Index("Date", null, null, null);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);

            // Otherwise, DateSortParm should be "Date"
            _controller.Index(null, null, null, null);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_SetsViewBagCurrentFilter()
        {
            _controller.Index(null, null, "test", null);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_NoMatchingSearch_ReturnsEmptyList()
        {
            var result = _controller.Index(null, null, "ZZZZZZZ", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.NotNull(model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Details(10) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Details_ValidId_IncludesEnrollments()
        {
            var result = _controller.Details(10) as ViewResult;
            var student = result.Model as Student;

            Assert.NotNull(student.Enrollments);
            Assert.True(student.Enrollments.Count > 0);
        }

        [Fact]
        public void Details_InvalidId_ThrowsException()
        {
            // Single() throws when no match found
            Assert.ThrowsAny<Exception>(() => _controller.Details(9999));
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithNewStudent()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavesStudentToDatabase()
        {
            var student = new Student
            {
                LastName = "Saved",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            _controller.Create(student);

            Assert.Contains(_context.Students, s => s.LastName == "Saved");
        }

        [Fact]
        public void Create_Post_MinValueEnrollmentDate_ReturnsViewWithError()
        {
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_TooEarlyEnrollmentDate_ReturnsViewWithError()
        {
            var student = new Student
            {
                LastName = "Bad",
                FirstMidName = "Date",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");

            var student = new Student
            {
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;
            Assert.NotNull(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(10) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            // Detach existing tracked entity to avoid tracking conflict
            var tracked = _context.Students.Find(10);
            _context.Entry(tracked).State = EntityState.Detached;

            var student = new Student
            {
                ID = 10,
                LastName = "UpdatedName",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            var result = _controller.Edit(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_MinValueEnrollmentDate_ReturnsViewWithError()
        {
            var student = new Student
            {
                ID = 10,
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");

            var student = new Student
            {
                ID = 10,
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Edit(student) as ViewResult;
            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(10) as ViewResult;

            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student.LastName);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(10);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesStudentFromDatabase()
        {
            _controller.DeleteConfirmed(10);

            var student = _context.Students.Find(10);
            Assert.Null(student);
        }

        [Fact]
        public void DeleteConfirmed_InvalidId_RedirectsToIndexWithError()
        {
            // Trying to delete a non-existent student should catch exception and redirect
            var result = _controller.DeleteConfirmed(9999);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        #endregion
    }
}

