using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new DepartmentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as List<Department>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var department = result.Model as Department;
            Assert.NotNull(department);
            Assert.Equal("English", department.Name);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorSelectList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var department = new Department
            {
                Name = "Physics",
                Budget = 150000m,
                StartDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(department);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesToDB()
        {
            var department = new Department
            {
                Name = "Chemistry",
                Budget = 120000m,
                StartDate = new DateTime(2023, 6, 1)
            };

            _controller.Create(department);
            Assert.Contains(_context.Departments, d => d.Name == "Chemistry");
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");

            var department = new Department();
            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_Post_WithInstructor_SavesCorrectly()
        {
            var department = new Department
            {
                Name = "Art",
                Budget = 80000m,
                StartDate = new DateTime(2023, 9, 1),
                InstructorID = 1
            };

            _controller.Create(department);
            var saved = _context.Departments.FirstOrDefault(d => d.Name == "Art");
            Assert.NotNull(saved);
            Assert.Equal(1, saved.InstructorID);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var department = result.Model as Department;
            Assert.NotNull(department);
            Assert.Equal("English", department.Name);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        #endregion

        #region Edit POST

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var tracked = _context.Departments.Find(1);
            _context.Entry(tracked).State = EntityState.Detached;

            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated English",
                Budget = 110000m,
                StartDate = new DateTime(2020, 1, 1)
            };

            var result = _controller.Edit(department);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");

            var department = new Department { DepartmentID = 1 };
            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var department = result.Model as Department;
            Assert.NotNull(department);
            Assert.Equal("English", department.Name);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _controller.DeleteConfirmed(1);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartmentFromDatabase()
        {
            _controller.DeleteConfirmed(1);
            Assert.Null(_context.Departments.Find(1));
        }

        #endregion
    }
}

