using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly HomeController _controller;

        public HomeControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new HomeController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            var result = _controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.NotNull(model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            var result = _controller.About() as ViewResult;
            var model = result.Model as List<EnrollmentDateGroup>;

            // Two students have 2020-09-01, one has 2021-09-01
            var group2020 = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2020, 9, 1));
            var group2021 = model.FirstOrDefault(g => g.EnrollmentDate == new DateTime(2021, 9, 1));

            Assert.NotNull(group2020);
            Assert.Equal(2, group2020.StudentCount);
            Assert.NotNull(group2021);
            Assert.Equal(1, group2021.StudentCount);
        }

        [Fact]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", _controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", _controller.ViewBag.Message);
        }
    }
}

