using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.TestHelpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _controller = new InstructorsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_SetsCourses()
        {
            var result = _controller.Index(1, null) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Courses);
            Assert.True(model.Courses.Any());
            Assert.Equal(1, (int)_controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Index_WithInstructorAndCourseId_SetsEnrollments()
        {
            var result = _controller.Index(1, 1050) as ViewResult;
            var model = result.Model as InstructorIndexData;

            Assert.NotNull(model.Enrollments);
            Assert.Equal(1050, (int)_controller.ViewBag.CourseID);
        }

        [Fact]
        public void Index_InstructorsOrderedByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result.Model as InstructorIndexData;
            var names = model.Instructors.Select(i => i.LastName).ToList();

            var sorted = names.OrderBy(n => n).ToList();
            Assert.Equal(sorted, names);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Get_PopulatesAssignedCourseData()
        {
            _controller.Create();

            var courses = _controller.ViewBag.Courses as List<AssignedCourseData>;
            Assert.NotNull(courses);
            Assert.Equal(3, courses.Count);
            Assert.All(courses, c => Assert.False(c.Assigned));
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_SavesToDB()
        {
            var instructor = new Instructor
            {
                LastName = "SavedInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            _controller.Create(instructor, null);
            Assert.Contains(_context.Instructors, i => i.LastName == "SavedInstructor");
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "WithCourses",
                FirstMidName = "Test",
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, new[] { "1050", "4022" });

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .FirstOrDefault(i => i.LastName == "WithCourses");

            Assert.NotNull(saved);
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");

            var instructor = new Instructor
            {
                HireDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Create(instructor, null) as ViewResult;
            Assert.NotNull(result);
        }

        #endregion

        #region Edit GET

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Abercrombie", instructor.LastName);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        #endregion

        #region Delete GET

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Delete POST

        [Fact]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            // Need to ensure instructor has no office assignment for this test
            var instructor = _context.Instructors
                .Include(i => i.OfficeAssignment)
                .First(i => i.ID == 1);

            var result = _controller.DeleteConfirmed(1);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructorFromDatabase()
        {
            _controller.DeleteConfirmed(1);
            Assert.Null(_context.Instructors.Find(1));
        }

        [Fact]
        public void DeleteConfirmed_InstructorAsDeptAdmin_ClearsDepartmentInstructorId()
        {
            // Set instructor 1 as department admin
            var dept = _context.Departments.Find(1);
            dept.InstructorID = 1;
            _context.SaveChanges();

            _controller.DeleteConfirmed(1);

            var updatedDept = _context.Departments.Find(1);
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}

